args.sparql:
SELECT ?countryLabel WHERE {
  wd:Q2534659 wdt:P27 wd:Q30.
  wd:Q30 rdfs:label ?countryLabel.
  FILTER(LANG(?countryLabel) = 'en')
}

SELECT ?rider ?countryLabel WHERE {
  wd:Q2534659 wdt:P27 wd:Q30;
             rdfs:label "Mike Day"@en.
  wd:Q30 rdfs:label ?countryLabel.
  FILTER(LANG(?countryLabel) = 'en')
}
